from langchain_core.runnables import RunnableLambda

STATIC_FALLBACK_MESSAGES = {
    "summarise": "I'm unable to generate a summary right now. Please try again in a few minutes.",
    "analyse":   "Analysis is temporarily unavailable. Your data has been saved and will be processed shortly.",
    "default":   "I'm experiencing technical difficulties. Please try again shortly.",
}

def static_fallback(task_type: str = "default"):
    def fn(input_):
        from langchain_core.messages import AIMessage
        return AIMessage(content=STATIC_FALLBACK_MESSAGES.get(task_type, STATIC_FALLBACK_MESSAGES["default"]))
    return RunnableLambda(fn)

# Build the full chain with graceful degradation
full_chain = (
    primary
    .with_fallbacks([
        fallback1,
        fallback2,
        static_fallback("summarise"),   # last resort — never raises
    ])
)

from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END

class State(TypedDict):
    query: str
    result: str
    provider_used: str
    error: str

def primary_node(state: State) -> dict:
    try:
        resp = primary_llm.invoke(state["query"])
        return {"result": resp.content, "provider_used": "opus", "error": ""}
    except Exception as exc:
        return {"error": str(exc), "result": ""}

def fallback_node(state: State) -> dict:
    try:
        resp = fallback_llm.invoke(state["query"])
        return {"result": resp.content, "provider_used": "haiku", "error": ""}
    except Exception as exc:
        return {"result": STATIC_FALLBACK_MESSAGES["default"], "provider_used": "static", "error": ""}

def route(state: State) -> Literal["fallback", "format"]:
    return "fallback" if state.get("error") else "format"

def format_node(state: State) -> dict:
    return {"result": f"[via {state['provider_used']}] {state['result']}"}

builder = StateGraph(State)
builder.add_node("primary",  primary_node)
builder.add_node("fallback", fallback_node)
builder.add_node("format",   format_node)
builder.set_entry_point("primary")
builder.add_conditional_edges("primary", route, {"fallback": "fallback", "format": "format"})
builder.add_edge("fallback", "format")
builder.add_edge("format",   END)
graph = builder.compile()

import hashlib
import time
from functools import lru_cache
from typing import Optional

class SimpleResponseCache:
    def __init__(self, ttl_seconds: int = 300):
        self._cache: dict[str, tuple[str, float]] = {}
        self.ttl = ttl_seconds

    def _key(self, query: str) -> str:
        return hashlib.sha256(query.encode()).hexdigest()

    def get(self, query: str) -> Optional[str]:
        k = self._key(query)
        if k in self._cache:
            response, ts = self._cache[k]
            if time.monotonic() - ts < self.ttl:
                return response
        return None

    def set(self, query: str, response: str):
        self._cache[self._key(query)] = (response, time.monotonic())

cache = SimpleResponseCache(ttl_seconds=300)

def cached_or_live(query: str) -> str:
    try:
        result = primary_llm.invoke(query).content
        cache.set(query, result)   # warm the cache on success
        return result
    except Exception:
        cached = cache.get(query)
        if cached:
            return f"[cached] {cached}"
        return STATIC_FALLBACK_MESSAGES["default"]

def should_fallback(exc: Exception) -> bool:
    """Return True if this exception should trigger a fallback (not a retry)."""
    import anthropic
    # Immediate fallback — do not retry these
    if isinstance(exc, anthropic.APIStatusError) and exc.status_code in {503, 529}:
        return True
    # Fallback after retry budget exhausted is handled by the caller
    return False

def should_retry(exc: Exception) -> bool:
    import anthropic
    if isinstance(exc, anthropic.RateLimitError):
        return True
    if isinstance(exc, anthropic.APIConnectionError):
        return True
    return False

def call_with_policy(fn, fallback_fn, max_retries: int = 3):
    """Retry transient errors; fall back on service unavailability."""
    import time
    for attempt in range(max_retries):
        try:
            return fn()
        except Exception as exc:
            if should_fallback(exc):
                return fallback_fn()   # immediate fallback
            if not should_retry(exc) or attempt == max_retries - 1:
                raise
            time.sleep(2 ** attempt)
    raise RuntimeError("Unreachable")

import logging
from dataclasses import dataclass, field
from collections import deque
import time

logger = logging.getLogger("fallback_monitor")

@dataclass
class FallbackMetrics:
    window_seconds: int = 300
    _events: deque = field(default_factory=deque)

    def record(self, provider: str, reason: str):
        now = time.monotonic()
        self._events.append((now, provider, reason))
        # Expire old events outside the window
        while self._events and now - self._events[0][0] > self.window_seconds:
            self._events.popleft()
        logger.warning(
            "fallback_activated",
            extra={"provider": provider, "reason": reason, "rate_per_min": self.rate_per_minute},
        )

    @property
    def rate_per_minute(self) -> float:
        return len(self._events) / (self.window_seconds / 60)

metrics = FallbackMetrics()

def instrumented_fallback(query: str) -> str:
    try:
        return primary_llm.invoke(query).content
    except Exception as exc:
        metrics.record(provider="primary", reason=type(exc).__name__)
        return fallback_llm.invoke(query).content

def build_prompt(query: str, model_tier: str) -> str:
    if model_tier == "primary":
        # Full context, nuanced instructions for capable model
        return f"""You are a senior analyst. Provide a comprehensive, nuanced analysis
of the following query, including edge cases and alternative perspectives.

Query: {query}"""
    elif model_tier == "fallback":
        # Simpler, more directive prompt for smaller model
        return f"Answer this question clearly and concisely: {query}"
    else:
        return query   # minimal prompt for last resort

def call_with_adapted_prompt(query: str) -> dict:
    for tier, model in [("primary", primary_llm), ("fallback", fallback_llm)]:
        try:
            prompt = build_prompt(query, tier)
            result = model.invoke(prompt)
            return {"content": result.content, "tier": tier}
        except Exception:
            continue
    return {"content": STATIC_FALLBACK_MESSAGES["default"], "tier": "static"}

from typing import TypedDict, Optional

class PipelineState(TypedDict):
    query: str
    step1_result: Optional[str]   # research
    step2_result: Optional[str]   # analysis
    step3_result: Optional[str]   # formatting
    final: str

def produce_best_available(state: PipelineState) -> dict:
    """Return the best partial result if the pipeline failed mid-way."""
    if state.get("step3_result"):
        return {"final": state["step3_result"]}
    if state.get("step2_result"):
        return {"final": f"[Partial — formatting unavailable]\n{state['step2_result']}"}
    if state.get("step1_result"):
        return {"final": f"[Partial — analysis unavailable]\n{state['step1_result']}"}
    return {"final": STATIC_FALLBACK_MESSAGES["default"]}

# Add as the terminal node in the graph — routes here when any step fails
builder.add_node("partial_fallback", produce_best_available)
